import json
from web3 import Web3

class EthereumWalletVerifier:
    def __init__(self, w3):
        self.w3 = w3
    
    def verify_signature(self, signed_message, signature):
        message = json.loads(signed_message)
        address = self.w3.eth.account.recoverHash(message['hash'], signature)
        return address == message['address']